import React, { useState, useEffect } from "react";
import { Dumbbell, Plus, Search, Video, X, Loader2, Save, Trash2 } from "lucide-react";
import { supabase } from "./lib/supabase"; // Asegúrate de que la ruta sea correcta

// Definimos la estructura de nuestro ejercicio basándonos en lo que lee la app
interface Exercise {
  id: string;
  name: string;
  category: string;
  description: string;
  video_url: string;
  thumbnail_url: string;
  kcal_estimate: number;
  time_estimate: number; // en segundos o minutos (por repetición/set)
  rest_time: number; // en segundos
}

export function WorkoutsPage() {
  const [exercises, setExercises] = useState<Exercise[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  // Estados para el Modal de Crear/Editar
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    category: "Pecho",
    description: "",
    video_url: "",
    thumbnail_url: "",
    kcal_estimate: 0.5,
    time_estimate: 3,
    rest_time: 60
  });

  const categories = ["Pecho", "Espalda", "Pierna", "Hombro", "Brazo", "Core", "Cardio", "CrossFit", "Otros"];

  // Cargar los ejercicios al iniciar
  useEffect(() => {
    fetchExercises();
  }, []);

  const fetchExercises = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('exercises')
        .select('*')
        .order('name');

      if (error) throw error;
      setExercises(data || []);
    } catch (error) {
      console.error("Error cargando ejercicios:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const { error } = await supabase
        .from('exercises')
        .insert([formData]);

      if (error) throw error;

      // Limpiar y cerrar
      setFormData({ name: "", category: "Pecho", description: "", video_url: "", thumbnail_url: "", kcal_estimate: 0.5, time_estimate: 3, rest_time: 60 });
      setIsModalOpen(false);
      fetchExercises(); // Recargar lista
    } catch (error) {
      console.error("Error guardando ejercicio:", error);
      alert("Hubo un error al guardar el ejercicio.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (window.confirm(`¿Estás seguro de que deseas eliminar el ejercicio "${name}"? Esto podría afectar a los historiales de los atletas.`)) {
      try {
        const { error } = await supabase.from('exercises').delete().eq('id', id);
        if (error) throw error;
        setExercises(exercises.filter(ex => ex.id !== id));
      } catch (error) {
        console.error("Error eliminando:", error);
      }
    }
  };

  // Filtrar por buscador
  const filteredExercises = exercises.filter(ex => 
    ex.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    ex.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500 relative">

      {/* Cabecera */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Biblioteca de Ejercicios</h1>
          <p className="text-gray-400 mt-1">Gestiona el catálogo disponible para la app móvil.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-[#E31C25] text-white px-6 py-3 rounded-xl font-bold hover:bg-[#A6151B] transition-all flex items-center gap-2 shadow-[0_0_15px_rgba(227,28,37,0.3)] shrink-0"
        >
          <Plus size={20} /> Añadir Ejercicio
        </button>
      </div>

      {/* Buscador */}
      <div className="bg-[#121212] border border-[#2a2a2a] p-4 rounded-2xl flex items-center gap-3">
        <Search className="text-gray-500 w-5 h-5" />
        <input 
          type="text"
          placeholder="Buscar por nombre o categoría..."
          className="bg-transparent border-none text-white outline-none w-full placeholder:text-gray-600"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Contenido Principal */}
      {loading ? (
        <div className="flex justify-center items-center py-20">
          <Loader2 className="w-10 h-10 text-[#E31C25] animate-spin" />
        </div>
      ) : filteredExercises.length === 0 ? (
        <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-2xl p-20 flex flex-col items-center text-center shadow-xl">
          <div className="w-24 h-24 bg-[#E31C25]/5 rounded-full flex items-center justify-center mb-6 border border-[#E31C25]/10">
            <Dumbbell className="w-12 h-12 text-[#E31C25] opacity-80" />
          </div>
          <h2 className="text-2xl font-bold text-white mb-2">Sin ejercicios</h2>
          <p className="text-gray-400 max-w-sm mx-auto">
            {searchTerm ? "No se encontraron resultados para tu búsqueda." : "Aún no has añadido ningún ejercicio. Empieza creando el primero."}
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredExercises.map((ex) => (
            <div key={ex.id} className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-2xl overflow-hidden hover:border-[#E31C25]/50 transition-all group">
              <div className="h-48 bg-[#121212] relative overflow-hidden">
                {ex.thumbnail_url ? (
                  <img src={ex.thumbnail_url} alt={ex.name} className="w-full h-full object-cover opacity-80 group-hover:scale-105 transition-transform duration-500" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <Dumbbell className="w-12 h-12 text-gray-700" />
                  </div>
                )}
                {ex.video_url && (
                  <div className="absolute top-3 right-3 bg-black/60 backdrop-blur-sm p-2 rounded-lg text-white">
                    <Video size={16} />
                  </div>
                )}
                <div className="absolute bottom-3 left-3 bg-[#E31C25] text-white text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wide">
                  {ex.category}
                </div>
              </div>
              <div className="p-5">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="text-lg font-bold text-white truncate pr-4">{ex.name}</h3>
                  <button onClick={() => handleDelete(ex.id, ex.name)} className="text-gray-500 hover:text-[#E31C25] transition-colors">
                    <Trash2 size={18} />
                  </button>
                </div>
                <p className="text-sm text-gray-400 line-clamp-2 mb-4 h-10">
                  {ex.description || "Sin descripción detallada."}
                </p>
                <div className="flex gap-4 border-t border-[#2a2a2a] pt-4">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-gray-500 uppercase font-bold">Kcal/Rep</span>
                    <span className="text-sm text-white font-medium">{ex.kcal_estimate}</span>
                  </div>
                  <div className="flex flex-col border-l border-[#2a2a2a] pl-4">
                    <span className="text-[10px] text-gray-500 uppercase font-bold">Tiempo</span>
                    <span className="text-sm text-white font-medium">{ex.time_estimate}s</span>
                  </div>
                  <div className="flex flex-col border-l border-[#2a2a2a] pl-4">
                    <span className="text-[10px] text-gray-500 uppercase font-bold">Descanso</span>
                    <span className="text-sm text-white font-medium">{ex.rest_time}s</span>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Modal de Creación (Deslizable desde la derecha) */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex justify-end">
          <div className="bg-[#121212] w-full max-w-md h-full border-l border-[#2a2a2a] flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">

            <div className="flex items-center justify-between p-6 border-b border-[#2a2a2a] bg-[#1a1a1a]">
              <h2 className="text-xl font-bold text-white">Nuevo Ejercicio</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-white bg-[#2a2a2a] p-2 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
              <form id="exercise-form" onSubmit={handleSubmit} className="space-y-5">

                <div>
                  <label className="block text-sm font-bold text-gray-400 mb-2">Nombre del ejercicio *</label>
                  <input required type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#E31C25] outline-none" placeholder="Ej: Press de Banca" />
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-400 mb-2">Categoría *</label>
                  <select required value={formData.category} onChange={(e) => setFormData({...formData, category: e.target.value})} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#E31C25] outline-none appearance-none">
                    {categories.map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-400 mb-2">ID de Video de YouTube (Opcional)</label>
                  <input type="text" value={formData.video_url} onChange={(e) => setFormData({...formData, video_url: e.target.value})} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#E31C25] outline-none" placeholder="Ej: dQw4w9WgXcQ" />
                  <p className="text-xs text-gray-500 mt-1">Solo el código del video, no la URL completa.</p>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-400 mb-2">URL de la Miniatura (Opcional)</label>
                  <input type="url" value={formData.thumbnail_url} onChange={(e) => setFormData({...formData, thumbnail_url: e.target.value})} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#E31C25] outline-none" placeholder="https://ejemplo.com/imagen.jpg" />
                </div>

                <div className="grid grid-cols-3 gap-4 p-4 bg-[#1a1a1a] rounded-xl border border-[#2a2a2a]">
                  <div>
                    <label className="block text-[10px] uppercase font-bold text-gray-400 mb-1 text-center">Kcal por Rep</label>
                    <input type="number" step="0.1" required value={formData.kcal_estimate} onChange={(e) => setFormData({...formData, kcal_estimate: parseFloat(e.target.value)})} className="w-full bg-[#121212] border border-[#2a2a2a] p-2 rounded-lg text-white text-center outline-none" />
                  </div>
                  <div>
                    <label className="block text-[10px] uppercase font-bold text-gray-400 mb-1 text-center">Tiempo (s)</label>
                    <input type="number" required value={formData.time_estimate} onChange={(e) => setFormData({...formData, time_estimate: parseInt(e.target.value)})} className="w-full bg-[#121212] border border-[#2a2a2a] p-2 rounded-lg text-white text-center outline-none" title="Segundos que tarda una repetición" />
                  </div>
                  <div>
                    <label className="block text-[10px] uppercase font-bold text-gray-400 mb-1 text-center">Descanso (s)</label>
                    <input type="number" required value={formData.rest_time} onChange={(e) => setFormData({...formData, rest_time: parseInt(e.target.value)})} className="w-full bg-[#121212] border border-[#2a2a2a] p-2 rounded-lg text-white text-center outline-none" />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-400 mb-2">Descripción e Instrucciones</label>
                  <textarea rows={4} value={formData.description} onChange={(e) => setFormData({...formData, description: e.target.value})} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl text-white focus:border-[#E31C25] outline-none resize-none" placeholder="Explica la técnica correcta, puntos clave y errores comunes..." />
                </div>

              </form>
            </div>

            <div className="p-6 border-t border-[#2a2a2a] bg-[#1a1a1a]">
              <button 
                form="exercise-form"
                type="submit"
                disabled={isSubmitting}
                className="w-full bg-[#E31C25] text-white font-bold py-4 rounded-xl hover:bg-[#A6151B] transition-colors flex items-center justify-center gap-2"
              >
                {isSubmitting ? <Loader2 className="animate-spin w-5 h-5" /> : <><Save size={20} /> Guardar Ejercicio</>}
              </button>
            </div>

          </div>
        </div>
      )}

    </div>
  );
}
